        #login h1 a, .login h1 a {
            background-image: url("data:image/svg+xml,%3Csvg width='123' height='62' viewBox='0 0 123 62' fill='none' xmlns='http://www.w3.org/2000/svg' xmlns:xlink='http://www.w3.org/1999/xlink'%3E%3Crect width='123' height='62' fill='url(%23pattern0_228_896)'/%3E%3Cdefs%3E%3Cpattern id='pattern0_228_896' patternContentUnits='objectBoundingBox' width='1' height='1'%3E%3Cuse xlink:href='%23image0_228_896' transform='matrix(0.000630081 0 0 0.00125 -0.00406504 0)'/%3E%3C/pattern%3E%3Cimage id='image0_228_896' width='1600' height='800' preserveAspectRatio='none' xlink:href='data:image/png;base64,'/%3E%3C/defs%3E%3C/svg%3E%0A");
            height: 62px;
            width: 123px;
            background-size: 100%;
            background-repeat: no-repeat;
